const cp = require('child_process');
const fs = require('fs');
const os = require('os');
const input = $input.first().json;
const message = (input.params && input.params.message) || input.message || '';
const project = (input.params && input.params.project) || input.project || '';
const projRoot = '__PROJECT_ROOT__';
const docsDir = '__DOCUMENTS_DIR__';

if (!message) return [{json:{status:'error',error:'Missing message'}}];

const cwd = project ? docsDir + '/' + project : projRoot;
const tmp = os.tmpdir() + '/chat-' + Date.now() + '.txt';

try {
  fs.writeFileSync(tmp, message);
  const result = cp.execSync('claude -p < "' + tmp.replace(/\/g, '/') + '"', {cwd, timeout: 300000, encoding: 'utf8', shell: true}).trim();
  try { fs.unlinkSync(tmp); } catch {}

  // Append to chat history
  const historyFile = projRoot + '/tasks/.chat-history.jsonl';
  const entry = JSON.stringify({ts: new Date().toISOString(), project: project || 'PA', message, result: result.substring(0, 500)});
  fs.appendFileSync(historyFile, entry + String.fromCharCode(10));

  return [{json:{status:'complete', response: result, project: project || 'PA', timestamp: new Date().toISOString()}}];
} catch(e) {
  try { fs.unlinkSync(tmp); } catch {}
  return [{json:{status:'error', error: (e.stderr || '') + e.message}}];
}
